#include <aie_api/aie.hpp>

void interpolate_kernel(input_stream<int16>* in, output_stream<int16>* out) {
  const int INTERPOLATION_FACTOR = 3;
  const int SAMPLES_PER_ITERATION = 16;

  aie::vector<int16, 16> input_vec;
  aie::vector<int16, 16> output_part1;
  aie::vector<int16, 16> output_part2;
  aie::vector<int16, 16> output_part3;

  for (int i = 0; i < 128; i++) {
    chess_prepare_for_pipelining
    input_vec = readincr_v<16>(in);

    for (int j = 0; j < 16; j++) {
      int16 sample = input_vec[j];
      int idx = j * 3;

      if (j < 5) {
        output_part1[idx % 16] = sample;
        output_part1[(idx + 1) % 16] = (sample >> 1);
        output_part1[(idx + 2) % 16] = 0;
      } else if (j < 11) {
        output_part2[(idx - 48) % 16] = sample;
        output_part2[(idx - 47) % 16] = (sample >> 1);
        output_part2[(idx - 46) % 16] = 0;
      } else {
        output_part3[(idx - 96) % 16] = sample;
        output_part3[(idx - 95) % 16] = (sample >> 1);
        output_part3[(idx - 94) % 16] = 0;
      }
    }

    writeincr_v<16>(out, output_part1);
    writeincr_v<16>(out, output_part2);
    writeincr_v<16>(out, output_part3);
  }
}

