#include <aie_api/aie.hpp>

void peak_detector(aie::input_stream<int16>* in, aie::output_stream<int16>* out) {
  int16 prev_sample = 0;
  int16 curr_sample = 0;
  int16 next_sample = 0;
  int peak_count = 0;

  // Read initial pair of samples
  prev_sample = readincr(in);
  curr_sample = readincr(in);

  // Process 512 samples total
  for (int i = 0; i < 510; i++) {
    chess_prepare_for_pipelining
    next_sample = readincr(in);

    // Detect local maximum: curr > prev AND curr > next
    if (curr_sample > prev_sample && curr_sample > next_sample) {
      writeincr(out, curr_sample);
      peak_count++;
    }

    // Shift window forward
    prev_sample = curr_sample;
    curr_sample = next_sample;
  }

  // Output final peak count as metadata
  writeincr(out, peak_count);
}

