#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

// Coefficient table: 128 taps for FIR-like operation
// Fits in 256 bytes, well under 32KB tile memory
constexpr int COEF_COUNT = 128;
constexpr int16 coefs[COEF_COUNT] = {
    16, 32, 48, 64, 80, 96, 112, 128,
    144, 160, 176, 192, 208, 224, 240, 256,
    272, 288, 304, 320, 336, 352, 368, 384,
    400, 416, 432, 448, 464, 480, 496, 512,
    528, 544, 560, 576, 592, 608, 624, 640,
    656, 672, 688, 704, 720, 736, 752, 768,
    784, 800, 816, 832, 848, 864, 880, 896,
    912, 928, 944, 960, 976, 992, 1008, 1024,
    1040, 1056, 1072, 1088, 1104, 1120, 1136, 1152,
    1168, 1184, 1200, 1216, 1232, 1248, 1264, 1280,
    1296, 1312, 1328, 1344, 1360, 1376, 1392, 1408,
    1424, 1440, 1456, 1472, 1488, 1504, 1520, 1536,
    1552, 1568, 1584, 1600, 1616, 1632, 1648, 1664,
    1680, 1696, 1712, 1728, 1744, 1760, 1776, 1792,
    1808, 1824, 1840, 1856, 1872, 1888, 1904, 1920
};

// Scaling factor and shift for output normalization
constexpr int16 SCALE_NUM = 16;
constexpr int SHIFT_BITS = 4;

void scale_shift_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    // Small local buffer: 64 samples = 128 bytes (single buffer)
    // NOT double buffered to stay well under 32KB
    constexpr int BUF_SIZE = 64;
    int16 buffer[BUF_SIZE];

    constexpr int ITERATIONS = 32;

    for (int iter = 0; iter < ITERATIONS; iter++) {
        // Read input samples
        for (int i = 0; i < BUF_SIZE; i++) {
            buffer[i] = readincr(in);
        }

        // Process: scale, apply coefficient phase, shift
        for (int i = 0; i < BUF_SIZE; i++) {
            int phase = i & (COEF_COUNT - 1);
            int32 acc = (int32)buffer[i] * SCALE_NUM;
            acc += coefs[phase];
            acc = acc >> SHIFT_BITS;

            // Saturate to int16 range
            int16 result;
            if (acc > 32767) result = 32767;
            else if (acc < -32768) result = -32768;
            else result = (int16)acc;

            writeincr(out, result);
        }
    }
}
