#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void decimate(input_stream<int16>* __restrict in, output_stream<int16>* __restrict out) {
    // Decimation factor: keep 1 of every M samples
    // Phase offset: which sample position to keep (0 to M-1)
    const int M = 4;
    const int PHASE = 0;

    // Process 128 output samples = 512 input samples
    const int OUTPUT_SAMPLES = 128;
    const int INPUT_SAMPLES = OUTPUT_SAMPLES * M;

    int phase_counter = PHASE;

    for (int i = 0; i < INPUT_SAMPLES; i++) {
        int16 sample = readincr(in);
        if (phase_counter == 0) {
            writeincr(out, sample);
        }
        phase_counter++;
        if (phase_counter >= M) {
            phase_counter = 0;
        }
    }
}
