void decimate_kernel(input_stream<uint16>* in, output_stream<uint16>* out) {
  const int DECIMATION_FACTOR = 4;
  const int OUTPUT_SAMPLES = 64;

  for (int n = 0; n < OUTPUT_SAMPLES; n++) {
    uint32_t accum = 0;

    for (int i = 0; i < DECIMATION_FACTOR; i++) {
      uint16 sample = readincr(in);
      accum += sample;
    }

    uint16 avg = (uint16)(accum / DECIMATION_FACTOR);
    writeincr(out, avg);
  }
}
